  "apple-earpods-with-lightning-connector-white-mmtn2zm-a": { highlights: ["Product Information", "Unlike traditional, circular earbuds, the design of the EarPods is defined by the geometry of the ear. Which makes them more comfortable for more people than any other earbud-style headphones.", "The speakers inside the EarPods have been engineered to maximise sound output and minimise sound loss, which means you get high-quality audio.", "The EarPods with Lightning Connector also include a built-in remote that lets you adjust the volume, control the playback of music and video, and answer or end calls with a pinch of the cord."], specs: [["Brand", "Apple"], ["Model", "MMTN2ZM/A"], ["Included Components", "Apple EarPods with Lightning Connector"], ["Item Weight", "60 g"], ["Net Quantity", "1"], ["Product Dimensions", "‎6 x 2.8 x 8.8 cm; 60 Grams"]], overview: "Unlike traditional, circular earbuds, the design of the EarPods is defined by the geometry of the ear. Which makes them more comfortable for more people than any other earbud-style headphones." },
  "samsung-galaxy-s23-ultra-5g-green": { highlights: ["About this item", "More innovation, less footprint – Galaxy S23 Ultra's striking symmetrical design returns with one major difference: recycled and eco-conscious materials. From the metal frame to the glass finish, it's polished with fresh new colors inspired by nature.", "Note's signature tool comes built in - The built-in S Pen keeps the legacy of Note alive. Plus, it helps you ditch the dependency on notebooks, making sketches and jotting notes effortless and eco-friendly.", "Low light. Camera. Action - A Pro-grade Camera grabs brighter photos and video, dusk to dawn. The intelligent pixel sensor adapts to low light with Nightography and the camera lens tones down flare for clearer captures", "200MP. Wow-worthy resolution - Resolution on the Wide-angle Camera has nearly doubled, delivering strikingly clear photos. Zoom and crop your shots for a whole new view —or leave it intact for brilliant detail, corner to corner.", "Power for those who don't pause - Your quest for epic mobile gaming is over. Snapdragon 8 Gen 2 Mobile Platform for Galaxy optimizes and streamlines your device for silky smooth games —without draining the battery"], specs: [["BRAND", "Samsung"], ["MODEL NAME", "Samsung Galaxy S23 Ultra 5G"], ["MODEL COLOR", "Green"], ["INTERNAL STORAGE", "256GB | 512GB"], ["BIOMETRICS", "Fingerprint Sensor"], ["BATTERY CAPACITY", "5000mAh"], ["WIRELESS CHARGING", "Yes"], ["What's In The Box", "Mobile Phone,Ejection Pin,Usb Cable,Manual,S pen"], ["DISPLAY SIZE", "6.8 inch (17.31cm)"], ["PANEL TYPE", "Dynamic AMOLED 2X display"], ["OS", "Android 13"], ["PROCESSOR BRAND", "Qualcomm"], ["PROCESSOR NAME", "Snapdragon® 8 Gen 2 Mobile Platform for Galaxy"], ["REAR CAMERA", "200MP + 10MP + 12MP + 10MP"], ["Country Of Origin", "India"], ["Product Weight", "233 gm"]] },
